const data = items[0].json;
const w = data.current;

const weatherCodes = {
  0: "Clear sky", 1: "Mainly clear", 2: "Partly cloudy", 3: "Overcast",
  45: "Foggy", 48: "Foggy", 51: "Light drizzle", 53: "Drizzle", 55: "Heavy drizzle",
  61: "Light rain", 63: "Rain", 65: "Heavy rain",
  71: "Light snow", 73: "Snow", 75: "Heavy snow",
  80: "Rain showers", 81: "Rain showers", 82: "Violent rain showers",
  95: "Thunderstorm", 96: "Thunderstorm with hail", 99: "Thunderstorm with heavy hail"
};

const condition = weatherCodes[w.weather_code] || "Unknown";

// Find the current hour's index in the hourly array to get the matching rain chance
const now = new Date();
const currentHourStr = now.toISOString().slice(0, 13); // e.g. "2026-07-15T14"
let rainChance = "N/A";
const hourlyTimes = data.hourly.time;
for (let i = 0; i < hourlyTimes.length; i++) {
  if (hourlyTimes[i].startsWith(currentHourStr)) {
    rainChance = data.hourly.precipitation_probability[i] + "%";
    break;
  }
}

const message = `Weather Update - Lodhran
Temperature: ${w.temperature_2m}°C (feels like ${w.apparent_temperature}°C)
Condition: ${condition}
Humidity: ${w.relative_humidity_2m}%
Wind: ${w.wind_speed_10m} km/h
Chance of Rain: ${rainChance}`;

return [{ json: { message } }];
